@module continuum  src=continuum.lua  loc=635  sha=eb14c68
@deps util, configManager, midiManager, trackerManager, commandManager, editCursor, trackerView, sampleManager, sampleView, swingEditor, curveEditor, trackerPage, samplePage

# Invariants & contracts (module)
  @map:invariant  entry point — owns lifecycle (Main runs once per ReaScript invocation), wires the layered manager stack, drives the render loop via reaper.defer
  @map:invariant  module load order is bottom-up: util first (everyone calls util.installHooks), commandManager before view layers (which self-register commands), pages last
  @map:invariant  one MIDI item per session — Main binds to the take at startup; selection changes mid-session require re-invoking the action
  @map:invariant  no teardown path — coord:quit() sets a flag that stops scheduling further defers; REAPER reclaims state on script unload
  @map:invariant  errors inside the defer loop surface through the same xpcall frame because each iteration reschedules itself

# Shapes
  @shape  fileOps = { copy(src,dst)->bool, move(src,dst)->bool, mkdir(dir), exists(path)->bool, hash(path)->string }
  @shape  chrome = { colour(name)->u32, pushChromeStyles(), popChromeStyles(), pushChromeWindow(), popChromeWindow(), verticalSeparator(), disabledIf(cond,fn), checkbox(label,v), radio(label,active), makeToolbar()->fn(segments), drawPicker(d), pickerIsActive()->bool, resetPickerActive(), requestPickerOpen(kind) }
  @shape  pickerSpec = { kind: string, heading: string, buttonLabel: string, items: [{label, key, group?=int, current?=bool}], onPick: fn(key), width?, minWidth?, maxWidth? }
  @shape  toolbarSegment = { id: string, render: fn, visible?: fn() -> bool }
  @shape  dispatchResult = { consumed: bool, commandHeld: bool }
  @shape  page = { renderToolbarBits(ctx), renderBody(ctx,w,h,dispatch), renderStatusBar(ctx), bind(...), unbind(), [renderFloating(ctx)] }

